@page "/catalog"
@using sv_5f985d5e3a8d4f66a5ba5d55d2d82651.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="_categories" OnApplyFilters="HandleApplyFilters" />
        </div>

        <div class="col-md-9">
            @if (_loading)
            {
                <div class="text-center my-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            else if (_result is not null)
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                Page="_result.Page"
                                PageSize="_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    /// <summary>Raised when a product card is clicked so the parent layout can navigate to a detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        try
        {
            _error = null;
            _loading = true;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _error = null;
            _loading = true;
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder – wire up a cart service when available
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadAsync();
    }
}

